// PAYROLL MODULE — UGANDA PAYE/NSSF COMPLIANT
// ═══════════════════════════════════════════════════════════════════════

// Uganda PAYE 2025/26 thresholds (UGX per month)
const PAYE_BRACKETS=[
  {min:0,max:235000,rate:0},
  {min:235001,max:335000,rate:0.10},
  {min:335001,max:410000,rate:0.20},
  {min:410001,max:10000000,rate:0.30},
  {min:10000001,max:Infinity,rate:0.40},
];

const calcPAYE=(grossTaxable)=>{
  let tax=0;
  for(const b of PAYE_BRACKETS){
    if(grossTaxable>b.min){
      const taxable=Math.min(grossTaxable,b.max)-b.min;
      tax+=taxable*b.rate;
    }
  }
  return Math.round(tax);
};

const NSSF_EMPLOYEE_RATE=0.05; // 5%
const NSSF_EMPLOYER_RATE=0.10; // 10%
// Uganda LST - tiered annual rates, deducted quarterly (÷4)
const calcLST=(monthlyGross)=>{
  // Annual LST based on monthly gross salary
  if(monthlyGross<=100000) return 0;
  if(monthlyGross<=200000) return 5000;
  if(monthlyGross<=300000) return 10000;
  if(monthlyGross<=400000) return 20000;
  if(monthlyGross<=500000) return 30000;
  if(monthlyGross<=600000) return 40000;
  if(monthlyGross<=700000) return 60000;
  if(monthlyGross<=800000) return 70000;
  if(monthlyGross<=900000) return 80000;
  if(monthlyGross<=1000000) return 90000;
  return 100000; // Over 1,000,000
};
const calcLSTMonthly=(monthlyGross)=>{
  // LST deducted ONCE annually in August (month index 7)
  const now=new Date();
  return now.getMonth()===7?calcLST(monthlyGross):0;
};
const calcLSTAugust=(monthlyGross)=>calcLST(monthlyGross); // full annual amount, deducted once in August
const LOCAL_SERVICE_TAX_THRESHOLD=100000; // min monthly gross for LST

const genEmployeeId=(name,dateJoined,seq)=>{
  const d=new Date(dateJoined);
  const dd=String(d.getDate()).padStart(2,"0");
  const mm=String(d.getMonth()+1).padStart(2,"0");
  const yy=String(d.getFullYear()).slice(-2);
  return `RL-EM${dd}${mm}${yy}${String(seq).padStart(3,"0")}`;
};

